  ('bookkeeper-moex-01780', 'bookkeeper', 'bookkeeper-moex-100-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '營利事業購置固定資產，其耐用年限超過 2 年，而支出金額不超過新臺幣多少元者，得以其成本列為當 年度費用？', '["6萬元", "8萬元", "10萬元", "20萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "19429a14fc1e", "answer_pdf_sha1": "35bec9c9a383", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "602", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
