  ('bookkeeper-moex-01782', 'bookkeeper', 'bookkeeper-moex-100-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依營利事業所得稅查核準則第81條規定，有關福利金提撥標準及費用認列規定，下列何者有誤？', '["增資資本額之百分之五限度內一次提撥", "創立時實收資本總額之百分之五限度內一次提撥", "每月營業收入總額內提撥百分之○‧○五至○‧一五", "下腳變價時，提撥百分之五十"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "19429a14fc1e", "answer_pdf_sha1": "35bec9c9a383", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "602", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01783', 'bookkeeper', 'bookkeeper-moex-100-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依營利事業所得稅查核準則第102條及第103條規定，下列何者錯誤？', '["災害損失應列為當年度損失。但損失較為鉅大者，得於三年內平均攤列", "員工因遭受災害傷亡，其由各該事業支付及取得醫院出具之證明書據之醫藥費，可核實認定該費用或 損失", "聘請外籍人員來臺服務，附有聘僱合約者，其到任之行李運送費用，可核實認定該費用或損失", "因業務需要免費發給員工之工作服，可核實認定該費用或損失"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "19429a14fc1e", "answer_pdf_sha1": "35bec9c9a383", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "602", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01784', 'bookkeeper', 'bookkeeper-moex-100-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '甲公司出售一間辦公室，買賣契約簽約日為98年12月30日，因一些因素考量，買賣雙方約定於99年1月 10日實際交付，另於100年2月1日辦理所有權移轉登記，依營利事業所得稅查核準則第24條之2規定， 其出售所得應歸屬那一年度？', '["97年度", "98年度", "99年度", "100年度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "19429a14fc1e", "answer_pdf_sha1": "35bec9c9a383", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "602", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01785', 'bookkeeper', 'bookkeeper-moex-100-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '營利事業因八八水災，當年度關係所得額之全部原始憑證滅失，該滅失憑證所屬期間之所得額，依營利 事業所得稅查核準則第11條規定，稽徵機關得依該事業以前幾個年度經稽徵機關核定純益率之平均數核 定之？', '["1年", "2年", "3年", "4年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "19429a14fc1e", "answer_pdf_sha1": "35bec9c9a383", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "602", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01786', 'bookkeeper', 'bookkeeper-moex-100-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依遺產及贈與稅法第6條及第7條規定，下列何者錯誤？', '["有遺囑執行人者，遺產稅之納稅義務人為繼承人", "贈與稅之納稅義務人除法律另有規定外，原則上為贈與人", "贈與人行蹤不明者，以受贈人為納稅義務人", "贈與人死亡時贈與稅尚未核課，以受贈人為納稅義務人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "19429a14fc1e", "answer_pdf_sha1": "35bec9c9a383", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "602", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01787', 'bookkeeper', 'bookkeeper-moex-100-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '某乙於100年10月16日星期日死亡，若某乙持有我國上市C公司之股票100萬股，試問應以那一天之 價格計算C公司股票價值課徵遺產稅？', '["10月14日之收盤價", "10月17日之開盤價", "10月17日之收盤價", "10月16日公司之資產淨值"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "19429a14fc1e", "answer_pdf_sha1": "35bec9c9a383", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "602", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01788', 'bookkeeper', 'bookkeeper-moex-100-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '謝先生以自己的資金2,000萬元無償替其朋友購買一塊土地，若該土地公告現值為800萬元，請問依照遺 產及贈與稅法規定，其視為贈與之金額為多少？', '["128萬元", "320萬元", "800萬元", "2,000萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "19429a14fc1e", "answer_pdf_sha1": "35bec9c9a383", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "602", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01789', 'bookkeeper', 'bookkeeper-moex-100-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '趙老大與其妻李仙女二人於長女結婚時分別贈與長女嫁妝 100萬元，也分別再給長女現金200萬元，假 設趙老大與其妻李仙女當年度都未贈與任何財產給任何人，有關當年度應計入贈與之淨額，下列何者正 確？', '["趙老大贈與淨額80萬元，李仙女0元", "趙老大贈與淨額100萬元，李仙女0元", "趙老大贈與淨額0元，李仙女80萬元", "趙老大贈與淨額0元，李仙女0元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "19429a14fc1e", "answer_pdf_sha1": "35bec9c9a383", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "602", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01790', 'bookkeeper', 'bookkeeper-moex-100-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '吉米是經常居住於臺中市之美國人，若吉米將其在中華民國境內之財產贈與給經常居住在高雄市的我國 國民張三，試問吉米應向下列那一個財政部國稅局申報贈與稅？', '["臺灣省中區國稅局", "臺灣省南區國稅局", "高雄市國稅局", "臺北市國稅局"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "19429a14fc1e", "answer_pdf_sha1": "35bec9c9a383", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "602", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01791', 'bookkeeper', 'bookkeeper-moex-100-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '王五參加99年記帳士考試及格，領有及格證書，準備於100年在臺北市松山區設立事務所執行業務，下 列有關敘述何者錯誤？', '["記帳士主管機關為財政部", "向財政部申請核發記帳士證書", "向臺北市國稅局辦理登錄執業", "向臺北市政府辦理登錄執業"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "b74f913e06f7", "answer_pdf_sha1": "79fc2cc5e98c", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "602", "s": "1101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
